// MARK: - AES Encryption Engine

final class AESEncryptionEngine {
    
    private let key: Data
    
    init(key: Data) {
        self.key = key
    }
    
    /// Generates a cryptographically secure random IV.
    private func generateIV() throws -> Data {
        var iv = Data(count: kCCBlockSizeAES128)
        let result = iv.withUnsafeMutableBytes { bytes in
            SecRandomCopyBytes(kSecRandomDefault, kCCBlockSizeAES128, bytes.baseAddress!)
        }
        guard result == errSecSuccess else {
            throw DataSecurityError.ivGenerationFailed
        }
        return iv
    }
    
    /// Encrypts plaintext data using AES-256-CBC with PKCS7 padding and a random IV.
    func encrypt(data: Data) throws -> EncryptedPayload {
        let iv = try generateIV()
        
        let bufferSize = data.count + kCCBlockSizeAES128
        var buffer = Data(count: bufferSize)
        var bytesEncrypted = 0
        
        let status = key.withUnsafeBytes { keyBytes in
            iv.withUnsafeBytes { ivBytes in
                data.withUnsafeBytes { dataBytes in
                    buffer.withUnsafeMutableBytes { bufferBytes in
                        CCCrypt(
                            CCOperation(kCCEncrypt),
                            CCAlgorithm(kCCAlgorithmAES),
                            CCOptions(kCCOptionPKCS7Padding),
                            keyBytes.baseAddress!,
                            kCCKeySizeAES256,
                            ivBytes.baseAddress!,
                            dataBytes.baseAddress!,
                            data.count,
                            bufferBytes.baseAddress!,
                            bufferSize,
                            &bytesEncrypted
                        )
                    }
                }
            }
        }
        
        guard status == kCCSuccess else {
            throw DataSecurityError.encryptionFailed(status)
        }
        
        buffer.removeSubrange(bytesEncrypted..<buffer.count)
        
        return EncryptedPayload(ciphertext: buffer, iv: iv)
    }
    
    /// Decrypts an encrypted payload back to plaintext data.
    func decrypt(payload: EncryptedPayload) throws -> Data {
        let ciphertext = payload.ciphertext
        let iv = payload.iv
        
        let bufferSize = ciphertext.count + kCCBlockSizeAES128
        var buffer = Data(count: bufferSize)
        var bytesDecrypted = 0
        
        let status = key.withUnsafeBytes { keyBytes in
            iv.withUnsafeBytes { ivBytes in
                ciphertext.withUnsafeBytes { dataBytes in
                    buffer.withUnsafeMutableBytes { bufferBytes in
                        CCCrypt(
                            CCOperation(kCCDecrypt),
                            CCAlgorithm(kCCAlgorithmAES),
                            CCOptions(kCCOptionPKCS7Padding),
                            keyBytes.baseAddress!,
                            kCCKeySizeAES256,
                            ivBytes.baseAddress!,
                            dataBytes.baseAddress!,
                            ciphertext.count,
                            bufferBytes.baseAddress!,
                            bufferSize,
                            &bytesDecrypted
                        )
                    }
                }
            }
        }
        
        guard status == kCCSuccess else {
            throw DataSecurityError.decryptionFailed(status)
        }
        
        buffer.removeSubrange(bytesDecrypted..<buffer.count)
        
        return buffer
    }
}

// MARK: - Data Security Module (Public API)

final class DataSecurityModule {
    
    static let shared = DataSecurityModule()
    
    private let keychainManager = KeychainManager.shared
    private let jsonEncoder = JSONEncoder()
    private let jsonDecoder = JSONDecoder()
    
    private var _encryptionEngine: AESEncryptionEngine?
    
    private init() {
        jsonEncoder.dateEncodingStrategy = .iso8601
        jsonDecoder.dateDecodingStrategy = .iso8601
    }
    
    /// Lazily initializes and caches the encryption engine.
    private func encryptionEngine() throws -> AESEncryptionEngine {
        if let engine = _encryptionEngine {
            return engine
        }
        let key = try keychainManager.getOrCreateEncryptionKey()
        let engine = AESEncryptionEngine(key: key)
        _encryptionEngine = engine
        return engine
    }
    
    // MARK: - Generic Encrypt / Decrypt
    
    /// Encrypts any Codable object and returns the encrypted payload as Data.
    func encrypt<T: Encodable>(_ object: T) throws -> Data {
        let plaintext = try jsonEncoder.encode(object)
        let engine = try encryptionEngine()
        let payload = try engine.encrypt(data: plaintext)
        let payloadData = try jsonEncoder.encode(payload)
        return payloadData
    }
    
    /// Decrypts Data back into the specified Codable type.
    func decrypt<T: Decodable>(_ data: Data, as type: T.Type) throws -> T {
        let payload = try jsonDecoder.decode(EncryptedPayload.self, from: data)
        let engine = try encryptionEngine()
        let plaintext = try engine.decrypt(payload: payload)
        let object = try jsonDecoder.decode(type, from: plaintext)
        return object
    }
    
    /// Encrypts a raw string and returns the encrypted payload as Data.
    func encryptString(_ string: String) throws -> Data {
        guard let data = string.data(using: .utf8) else {
            throw DataSecurityError.dataEncodingFailed
        }
        let engine = try encryptionEngine()
        let payload = try engine.encrypt(data: data)
        return try jsonEncoder.encode(payload)
    }
    
    /// Decrypts Data back into a String.
    func decryptString(_ data: Data) throws -> String {
        let payload = try jsonDecoder.decode(EncryptedPayload.self, from: data)
        let engine = try encryptionEngine()
        let plaintext = try engine.decrypt(payload: payload)
        guard let string = String(data: plaintext, encoding: .utf8) else {
            throw DataSecurityError.dataDecodingFailed
        }
        return string
    }
    
    // MARK: - User Credentials
    
    func saveUserCredentials(_ credentials: UserCredentials) throws {
        let encryptedData = try encrypt(credentials)
        try keychainManager.saveToKeychain(
            data: encryptedData,
            forIdentifier: SensitiveDataType.userCredentials.rawValue
