        let encryptedData = try encrypt(token)
        try keychainManager.saveToKeychain(data: encryptedData, forIdentifier: identifier)
    }
    
    func loadPaymentToken(tokenId: String) throws -> PaymentToken {
        let identifier = "\(SensitiveDataType.paymentToken.rawValue)_\(tokenId)"
        let encryptedData = try keychainManager.retrieveFromKeychain(forIdentifier: identifier)
        return try decrypt(encryptedData, as: PaymentToken.self)
    }
    
    func deletePaymentToken(tokenId: String) throws {
        let identifier = "\(SensitiveDataType.paymentToken.rawValue)_\(tokenId)"
        try keychainManager.deleteFromKeychain(forIdentifier: identifier)
    }
    
    // MARK: - Personal Information
    
    func savePersonalInformation(_ info: PersonalInformation) throws {
        let encryptedData = try encrypt(info)
        try keychainManager.saveToKeychain(
            data: encryptedData,
            forIdentifier: SensitiveDataType.personalInformation.rawValue
        )
    }
    
    func loadPersonalInformation() throws -> PersonalInformation {
        let encryptedData = try keychainManager.retrieveFromKeychain(
            forIdentifier: SensitiveDataType.personalInformation.rawValue
        )
        return try decrypt(encryptedData, as: PersonalInformation.self)
    }
    
    func deletePersonalInformation() throws {
        try keychainManager.deleteFromKeychain(
            forIdentifier: SensitiveDataType.personalInformation.rawValue
        )
    }
    
    // MARK: - Secure Local File Storage (for larger data)
    
    /// Encrypts and writes data to a file in the app's protected documents directory.
    func encryptAndSaveToFile<T: Encodable>(_ object: T, filename: String) throws {
        let encryptedData = try encrypt(object)
        let fileURL = try secureFileURL(for: filename)
        try encryptedData.write(to: fileURL, options: [.atomic, .completeFileProtection])
    }
    
    /// Reads and decrypts data from a file in the app's protected documents directory.
    func loadAndDecryptFromFile<T: Decodable>(filename: String, as type: T.Type) throws -> T {
        let fileURL = try secureFileURL(for: filename)
        let encryptedData = try Data(contentsOf: fileURL)
        return try decrypt(encryptedData, as: type)
    }
    
    /// Securely deletes a file by overwriting with random data before removing.
    func secureDeleteFile(filename: String) throws {
        let fileURL = try secureFileURL(for: filename)
        let fileManager = FileManager.default
        
        guard fileManager.fileExists(atPath: fileURL.path) else { return }
        
        // Overwrite with random data before deletion
        if let fileSize = try? fileManager.attributesOfItem(atPath: fileURL.path)[.size] as? Int,
           fileSize > 0 {
            var randomData = Data(count: fileSize)
            _ = randomData.withUnsafeMutableBytes { bytes in
                SecRandomCopyBytes(kSecRandomDefault, fileSize, bytes.baseAddress!)
            }
            try randomData.write(to: fileURL, options: .atomic)
        }
        
        try fileManager.removeItem(at: fileURL)
    }
    
    private func secureFileURL(for filename: String) throws -> URL {
        let documentsDirectory = FileManager.default.urls(
            for: .applicationSupportDirectory,
            in: .userDomainMask
        ).first!
        
        let secureDirectory = documentsDirectory.appendingPathComponent("SecureData", isDirectory: true)
        
        if !FileManager.default.fileExists(atPath: secureDirectory.path) {
            try FileManager.default.createDirectory(
                at: secureDirectory,
                withIntermediateDirectories: true,
                attributes: [.protectionKey: FileProtectionType.complete]
            )
        }
        
        return secureDirectory.appendingPathComponent(filename)
    }
    
    // MARK: - Reset
    
    /// Wipes all secured data. Typically used on logout or account deletion.
    func wipeAllSecureData() {
        _encryptionEngine = nil
        keychainManager.resetAll()
        
        if let secureDir = try? secureFileURL(for: "").deletingLastPathComponent() {
            try? FileManager.default.removeItem(at: secureDir)
        }
    }
}

